tent, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$ba671c41-8479-4805-8bca-f767791725bb$tag$, $tag$2026012300078$tag$, $tag$Juliana (5511992663163)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Bom dia \nEspero que estejam bem \nGostaria de falar com um consultor \nAnteriormente estava falando com a Karina \nQuero dar sequência na minha inscrição ( Pós)Educação Clássica Cristã","time":"23/01/2026 10:18:56"},{"role":"client","text":"🌟 Bom dia Juliana! Que alegria ter você aqui com a gente! 🙌","time":"23/01/2026 10:18:57"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"23/01/2026 10:19:01"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"23/01/2026 10:19:05"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"23/01/2026 10:19:12"},{"role":"client","text":"Faculdade","time":"23/01/2026 10:19:41"},{"role":"client","text":"Olá! Juliana!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"23/01/2026 10:19:43"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"23/01/2026 10:19:47"},{"role":"client","text":"Saber sobre os cursos","time":"23/01/2026 10:20:03"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"23/01/2026 10:20:07"},{"role":"client","text":"Pós-Graduação","time":"23/01/2026 10:20:21"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"23/01/2026 10:20:26"},{"role":"client","text":"Educação Cristã Clássica","time":"23/01/2026 10:20:44"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"23/01/2026 10:20:45"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"23/01/2026 10:20:49"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"23/01/2026 10:21:07"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"23/01/2026 10:21:08"},{"role":"client","text":"Obrigada \nNo aguardo","time":"23/01/2026 10:21:27"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"23/01/2026 10:26:32"},{"role":"agent","text":"*Thayanne Sales:* Vamos prosseguir com a sua matricula?","time":"23/01/2026 10:27:08","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* No que posso lhe ajudar?","time":"23/01/2026 10:27:13","feedback":"⚠️ Pergunta Genérica: Evite perguntas que podem ser respondidas com \"não\". Tente: \"Qual sua maior motivação para estudar hoje?\""},{"role":"client","text":"Sim\nObrigada pelo retorno","time":"23/01/2026 10:29:23"},{"role":"client","text":"Quero me inscrever para pós Educação Clássica Cristã \n\nMe confirma… online né ??\n16 meses ??\nE até hoje vocês estão apresentando um valor diferenciado","time":"23/01/2026 10:30:58"},{"role":"client","text":"Estou trabalhando na coordenação de  um colégio Educação Clássica Cristã","time":"23/01/2026 10:31:54"},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"23/01/2026 10:35:57","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Educação Cristã Clássica* - Disciplinas do Curso:\n\nBase: Filosófica Teológica\nCosmovisão Cristã e Filosofia Reformada – Ms. Vinicius Pimentel\nFundamentos da Pedagogia Cristã – Ms. Igor Miguel\nA Paideia de Deus (Educação Pactual) – Ms. Rodrigo Brotto\n\nBase: Histórica Pedagógica Clássica&nbsp;\nHistória da Educação Clássica – Ms. Lucas Evangelista\nFundamentos Pedagógicos das Sete Artes Liberais – Ms. Rodrigo Brotto\nVerdade, Bondade e Beleza: A Formação do Imaginário – Ms. Raquel Van De Burgt\n\nBase: Metodológica Cristã Clássica\nAplicando o Trivium no Contexto Educacional – Ms. Renata Costa\nAprendendo a Ler Classicamente (Alfabetização Clássica) – Esp. Leandro Ribeiro\nDisciplina na Educação (Pastoreando o Coração da Criança) – Ms. Kenneth V. Trotter\nDesenvolvimento do Currículo - Kim Bedinfield\n\nObs: Professores sujeitos a alterações. ","time":"23/01/2026 10:36:01","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. Esta com condições especiais com 50% de desconto e as mensalidades está por R$ 239,58 \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para abril/2026.\n\n\n🎁 Cupom de Desconto ECC: *BOLSA50*\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_19\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"23/01/2026 10:36:07","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Ok … ficou claro \nVou iniciar a matrícula \nQualquer dúvida eu chamo \nObrigada","time":"23/01/2026 10:43:40"},{"role":"agent","text":"*Thayanne Sales:* Ta certo, qualquer dúvida estou a disposição.","time":"23/01/2026 10:51:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Thay Anne","time":"23/01/2026 10:59:25"},{"role":"agent","text":"*Thayanne Sales:* Oi","time":"23/01/2026 11:00:24","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Tem uma parte para enviar alguns documentos \nEstou na escola até o final do dia \nNão consigo enviar agora \nPosso fazer isso a noite quando chegar em casa??\n\nMais dar sequência e já fazer o pagamento","time":"23/01/2026 11:00:33"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/69737f2adb8e176a75006107) | Essa parte final","time":"23/01/2026 11:01:14"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.