INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$77dfe1e8-ea31-4b7c-8a72-c674020205d2$tag$, $tag$2026012300089$tag$, $tag$Tatiana Kelly (5585988326852)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Educacao Crista Classica e quero mais informações.","time":"23/01/2026 11:02:10"},{"role":"client","text":"🌟 Bom dia Tatiana Kelly! Que alegria ter você aqui com a gente! 🙌","time":"23/01/2026 11:02:10"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"23/01/2026 11:02:15"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"23/01/2026 11:02:18"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"23/01/2026 11:02:22"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"23/01/2026 11:02:28"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"23/01/2026 11:02:34"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"23/01/2026 11:02:35"},{"role":"client","text":"Sim, concordo","time":"23/01/2026 11:02:48"},{"role":"client","text":"✅ Obrigado, Tatiana Kelly! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"23/01/2026 11:02:49"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"23/01/2026 11:02:53"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"23/01/2026 11:03:15"},{"role":"client","text":"Olá! Tatiana Kelly!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"23/01/2026 11:03:16"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"23/01/2026 11:03:20"},{"role":"client","text":"Saber sobre os cursos","time":"23/01/2026 11:03:45"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"23/01/2026 11:03:49"},{"role":"client","text":"Pós-Graduação","time":"23/01/2026 11:04:04"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"23/01/2026 11:04:08"},{"role":"client","text":"Educação Cristã Clássica","time":"23/01/2026 11:04:21"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"23/01/2026 11:04:22"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"23/01/2026 11:04:26"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"23/01/2026 11:04:53"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"23/01/2026 11:04:55"},{"role":"client","text":"Ok","time":"23/01/2026 11:05:15"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"23/01/2026 11:13:14"},{"role":"agent","text":"*Thayanne Sales:* &nbsp;Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"23/01/2026 11:13:25","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"23/01/2026 11:13:35","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Educação Cristã Clássica* - Disciplinas do Curso:\n\nBase: Filosófica Teológica\nCosmovisão Cristã e Filosofia Reformada – Ms. Vinicius Pimentel\nFundamentos da Pedagogia Cristã – Ms. Igor Miguel\nA Paideia de Deus (Educação Pactual) – Ms. Rodrigo Brotto\n\nBase: Histórica Pedagógica Clássica&nbsp;\nHistória da Educação Clássica – Ms. Lucas Evangelista\nFundamentos Pedagógicos das Sete Artes Liberais – Ms. Rodrigo Brotto\nVerdade, Bondade e Beleza: A Formação do Imaginário – Ms. Raquel Van De Burgt\n\nBase: Metodológica Cristã Clássica\nAplicando o Trivium no Contexto Educacional – Ms. Renata Costa\nAprendendo a Ler Classicamente (Alfabetização Clássica) – Esp. Leandro Ribeiro\nDisciplina na Educação (Pastoreando o Coração da Criança) – Ms. Kenneth V. Trotter\nDesenvolvimento do Currículo - Kim Bedinfield\n\nObs: Professores sujeitos a alterações. ","time":"23/01/2026 11:13:39","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. Esta com condições especiais com 50% de desconto e as mensalidades está por R$ 239,58 \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para abril/2026.\n\n\n🎁 Cupom de Desconto ECC: *BOLSA50*\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_19\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"23/01/2026 11:13:45","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Atendimento Finalizado!\n\nTatiana Kelly, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"26/01/2026 08:48:56"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"26/01/2026 08:48:57"},{"role":"client","text":"Tatiana Kelly, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"26/01/2026 09:03:58"}]$tag$, $tag$2026-01-23 11:02:10+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
