INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$7779a4de-1df6-4c80-89a0-e569e29fdb17$tag$, $tag$2026012300104$tag$, $tag$Gabriela Rodrigues (5588992917586)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página de Psicopedagogia e quero mais informações.","time":"23/01/2026 11:56:02"},{"role":"client","text":"🌟 Bom dia Gabriela Rodrigues! Que alegria ter você aqui com a gente! 🙌","time":"23/01/2026 11:56:03"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"23/01/2026 11:56:07"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"23/01/2026 11:56:11"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"23/01/2026 11:56:15"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"23/01/2026 11:56:21"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"23/01/2026 11:56:27"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"23/01/2026 11:56:28"},{"role":"client","text":"Sim, concordo","time":"23/01/2026 11:56:39"},{"role":"client","text":"✅ Obrigado, Gabriela Rodrigues! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"23/01/2026 11:56:40"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"23/01/2026 11:56:44"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"23/01/2026 11:56:58"},{"role":"client","text":"Olá! Gabriela Rodrigues!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"23/01/2026 11:56:59"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"23/01/2026 11:57:03"},{"role":"client","text":"Saber sobre os cursos","time":"23/01/2026 11:57:15"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"23/01/2026 11:57:19"},{"role":"client","text":"Pós-Graduação","time":"23/01/2026 11:57:28"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"23/01/2026 11:57:32"},{"role":"client","text":"Psicopedagogia","time":"23/01/2026 11:57:53"},{"role":"client","text":"Essa pós é ideal para quem deseja compreender e intervir nos processos de aprendizagem com uma abordagem ética, cristã e prática.\n\n 🧠 100% online, estude no seu ritmo\n 🎓 Professores experientes e materiais atualizados\n 📅 Aulas iniciam em agosto\n 💰 Condição promocional especial para novas matrículas","time":"23/01/2026 11:57:54"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"23/01/2026 11:57:58"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"23/01/2026 11:58:15"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"23/01/2026 11:58:16"},{"role":"client","text":"Qual o valor da pós?","time":"23/01/2026 11:58:38"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"23/01/2026 12:00:31"},{"role":"agent","text":"*Thayanne Sales:* *PÓS-GRADUAÇÃO EM PSICOPEDAGOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 18 meses.\n\nCARGA HORÁRIA\n630 horas\n\nDISCIPLINAS\n12 disciplinas obrigatórias e 1  disciplina optativa\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"23/01/2026 12:00:56","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Disciplinas da Pós em Psicopedagogia*\n\nBASE: FILOSÓFICA TEOLÓGICA\n\n1-Introdução à Cosmovisão Cristã - Dr. Bruno Ribeiro\n2-Fundamentos Filosóficos e Metodológicos de uma Pedagogia Cristã - Me. Thiago Dutra\n3-Introdução à Educação Cristã Clássica - Me. Thiago Dutra\n\nBASE: PSICOPEDAGOGIA E DESENVOLVIMENTO\n\n4-Fundamentos da Psicopedagogia - Ma. Luciana Siqueira\n5-Alfabetização Fônica - Esp. Finlândia de Oliveira das Chagas\n6-Aprendizagem da Matemática - Esp. Úrsula Keyla\n7-Desenvolvimento Cognitivo e Neurociência - Alessandra Schneider\n8-Síndromes, Transtornos e Dificuldades de Aprendizagem - Ma. Fabiana Josefa Sousa\n\nBASE: Avaliação, Diagnóstico e Mediação Psicopedagógica\n\n9-Teoria da Experiência de Aprendizagem Mediada em Feuerstein - Me. David Sasson/ Marcia Macionk\n10-Avaliação e Intervenção Psicopedagógica - Dra. Edith Rubstein\n11-Âmbitos de atuação do Psicopedagogo e Educação Formal - Esp. Karine Canani\n12-Temas contemporâneos em psicopedagogia:\n1- Inclusão e atuação do Psicopedagogo - Dra. Cristiane Souza;\n2- Uso das tecnologias e asimplicações para aprendizagem - Esp. Letícia Ruiz\n3- Altas Habilidades e Superdotação - Vera Pereira\n4- Direito Educacional Aplicado - Esp. Vladimir Miná\n5- Disciplina baseada em Virtudes -  Esp. LetíciaRuiz\n\n13 Seminário de práticas Psicopedagógicas - Ma. Fabiana Josefa Sousa/ Ma. Luciana Siqueira","time":"23/01/2026 12:01:00","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Psicopedagogia  está em 18 mensalidades de *R$ 479,16*. Esse mês esta com condições especiais com 50% de desconto e as mensalidades está por R$ 239,58 \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para abril/2026.\n\n\n🎁 Cupom de Desconto da Pós em Psicopedagogia: *BOLSA50*\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_26\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"23/01/2026 12:01:07","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Atendimento Finalizado!\n\nGabriela Rodrigues, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"26/01/2026 08:49:19"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"26/01/2026 08:49:20"},{"role":"client","text":"Gabriela Rodrigues, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"26/01/2026 09:04:23"}]$tag$, $tag$2026-01-23 11:56:02+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
