INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$23cc7a52-16fe-44af-b355-c9baeaab4f8c$tag$, $tag$2026012300157$tag$, $tag$Jefferson (5521982345705)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"23/01/2026 16:19:27"},{"role":"client","text":"🌟 Boa tarde Jefferson! Que alegria ter você aqui com a gente! 🙌","time":"23/01/2026 16:19:28"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"23/01/2026 16:19:32"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"23/01/2026 16:19:36"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"23/01/2026 16:19:40"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"23/01/2026 16:19:46"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"23/01/2026 16:19:52"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"23/01/2026 16:19:53"},{"role":"client","text":"Sim, concordo","time":"23/01/2026 16:20:28"},{"role":"client","text":"✅ Obrigado, Jefferson! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"23/01/2026 16:20:29"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"23/01/2026 16:20:34"},{"role":"client","text":"qual o preço da pós-graudação?","time":"23/01/2026 16:21:07"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"23/01/2026 16:21:08"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"23/01/2026 16:21:08"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"23/01/2026 16:21:27"},{"role":"client","text":"Olá! Jefferson!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"23/01/2026 16:21:28"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"23/01/2026 16:21:32"},{"role":"client","text":"Falar com um atendente","time":"23/01/2026 16:21:50"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"23/01/2026 16:21:51"},{"role":"client","text":"Qual o  valor Pós-Graduação em Educação Cristã?","time":"23/01/2026 16:23:39"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"23/01/2026 16:24:54"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n","time":"23/01/2026 16:25:19","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"23/01/2026 16:25:29","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"23/01/2026 16:25:36","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Preciso pensar.","time":"23/01/2026 16:37:32"},{"role":"client","text":"Atendimento Finalizado!\n\nJefferson, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"26/01/2026 16:32:09"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"26/01/2026 16:32:10"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"26/01/2026 16:35:35"},{"role":"client","text":"Sua sessão expirou!","time":"26/01/2026 16:37:37"}]$tag$, $tag$2026-01-23 16:19:27+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 10, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$8419ebb9-7389-44d6-a050-c47d59c90403$tag$, $tag$2026012300034$tag$, $tag$Iago Azevedo (5584998014374)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"agent","text":"*Karina Pimentel:* Olá Bom dia me chamo Karina Pimentel da Cidade Viva! \n","time":"23/01/2026 08:40:25","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia 😃","time":"23/01/2026 08:41:20"},{"role":"agent","text":"*Karina Pimentel:* Olá, Sr Iago!\n\nNotamos que a sua Renovação de Matrícula ainda não foi realizada e estou entrando em contato para saber se está tudo certo ou se podemos ajudar em algo.\n\nA sua trajetória conosco é importante, e estamos à disposição para esclarecer dúvidas sobre prazos, procedimentos ou qualquer outra necessidade para a continuidade dos seus estudos.\n\nMe diga, sua não renovação foi por motivo técnico ou tem alguma outra necessidade que eu possa te ajudar a resolver?","time":"23/01/2026 09:19:34","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Perfeito, eu não vi que estava no período de renovação","time":"23/01/2026 09:21:20"},{"role":"client","text":"abri o app agora e vi que tem um valor de R$ 408,22 a ser pago, é a renovação né?","time":"23/01/2026 09:21:40"},{"role":"agent","text":"*Karina Pimentel:* Isso!","time":"23/01/2026 09:22:49","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Teve um reajuste !","time":"23/01/2026 09:23:01","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok, eu não tenho como pagar agora, recebo após o dia 05/02, pode ajustar a data para dia 06/02 por exemplo?","time":"23/01/2026 09:23:27"},{"role":"agent","text":"*Karina Pimentel:* Pode sim, porém tem os juros! Mais no dia 05/02 entre em contato ok!","time":"23/01/2026 09:40:00","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"😭","time":"23/01/2026 09:45:01"},{"role":"agent","text":"*Karina Pimentel:* No dia 05/02 retorno para o senhor ok!","time":"23/01/2026 09:49:09","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Certinho, obrigado","time":"23/01/2026 09:51:39"},{"role":"agent","text":"*Karina Pimentel:* De nada!","time":"23/01/2026 10:20:34","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Até breve!","time":"23/01/2026 10:20:37","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Deus abençoe!","time":"23/01/2026 10:20:41","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nIago Azevedo, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"23/01/2026 10:20:43"}]$tag$, $tag$2026-01-23 08:40:25+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 9, 2, 9, 9, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$631f5506-c393-459b-be70-3cacd68f2859$tag$, $tag$2026012300036$tag$, $tag$Israel.imÃ³veis (5584998121828)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"agent","text":"*Karina Pimentel:* Olá Bom dia me chamo Karina Pimentel da Cidade Viva! \n","time":"23/01/2026 08:42:12","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ótimo! Você chegou ao lugar certo! Meu nome é Israel Rodrigues, sou Corretor de Imóveis da REMAX MEGA; te retornarei tão logo possível. Enquanto isso, te convido a visitar o meu perfil no Instagram ou clicar no link abaixo para conferir os imóveis a disposição disponha!\nUm abraço!\n\nConfira abaixo ⬇️ \nwww.instagram.com/israelcorretordeimoveis\nwww.brokerapp.com.br/israel-nascimento-rodrigues","time":"23/01/2026 08:42:21"},{"role":"client","text":"Olá, bom dia Karina!","time":"23/01/2026 09:04:14"},{"role":"agent","text":"*Karina Pimentel:* Olá, senhor Sr Israel!\n\nNotamos que a sua Renovação de Matrícula ainda não foi realizada e estou entrando em contato para saber se está tudo certo ou se podemos ajudar em algo.\n\nA sua trajetória conosco é importante, e estamos à disposição para esclarecer dúvidas sobre prazos, procedimentos ou qualquer outra necessidade para a continuidade dos seus estudos.\n\nMe diga, sua não renovação foi por motivo técnico ou tem alguma outra necessidade que eu possa te ajudar a resolver?\nResponder","time":"23/01/2026 09:14:30","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Não, não, estava com algumas situações de saúde, mas, melhorando graças a Deus. Vou renovar sim.","time":"23/01/2026 09:26:27"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"23/01/2026 09:49:29","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Já está disponível no Web aluno, pedimos que por gentileza após o pagamento nos confirme aqui ok! Fique atento as aulas retornam em 02/02.","time":"23/01/2026 09:50:48","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Pagamento realizado","time":"23/01/2026 09:57:54"},{"role":"client","text":"Sim, obrigado!","time":"23/01/2026 09:58:09"},{"role":"agent","text":"*Karina Pimentel:* Maravilha meu irmão!","time":"23/01/2026 10:18:12","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Bons estudos!","time":"23/01/2026 10:18:20","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Deus abençoe!","time":"23/01/2026 10:18:26","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Obrigado Karina!\nDeus te abençoe também.","time":"23/01/2026 10:46:12"},{"role":"client","text":"Atendimento Finalizado!\n\nIsrael.imÃ³veis, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"23/01/2026 11:05:32"}]$tag$, $tag$2026-01-23 08:42:12+00$tag$, FALSE, FALSE, 7.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 5, 2, 9, 7, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$d0ac2f86-ad7e-405d-b4f1-0284a9942446$tag$, $tag$2026012300037$tag$, $tag$JessÃ© De Souza (5584987142502)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"agent","text":"*Karina Pimentel:* Olá Bom dia me chamo Karina Pimentel da Cidade Viva! \n","time":"23/01/2026 08:43:14","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia!","time":"23/01/2026 08:46:36"},{"role":"agent","text":"*Karina Pimentel:* \nOlá!\n\nNotamos que a sua Renovação de Matrícula ainda não foi realizada e estou entrando em contato para saber se está tudo certo ou se podemos ajudar em algo.\n\nA sua trajetória conosco é importante, e estamos à disposição para esclarecer dúvidas sobre prazos, procedimentos ou qualquer outra necessidade para a continuidade dos seus estudos.\n\nMe diga, sua não renovação foi por motivo técnico ou tem alguma outra necessidade que eu possa te ajudar a resolver?","time":"23/01/2026 09:17:53","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Karina, eu na verdade enviei um e-mail solicitando minha renovação de matrícula, porque fui orientado a fazer isso pelo Victor","time":"23/01/2026 09:19:18"},{"role":"client","text":"Victor Moreira","time":"23/01/2026 09:19:29"},{"role":"client","text":"Ontem Abel Alves respondeu meu e-mail falando que a rematrícula foi efetuada","time":"23/01/2026 09:20:37"},{"role":"client","text":"Você poderia verificar, por favor?","time":"23/01/2026 09:20:44"},{"role":"client","text":"Porque sou bolsista","time":"23/01/2026 09:22:03"},{"role":"agent","text":"*Karina Pimente