INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$4712472f-7b69-45b6-b026-8d1f7cb8685d$tag$, $tag$2026012300043$tag$, $tag$Jonnyert Lima - Presencial e Online (5583998184070)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"agent","text":"*Karina Pimentel:* Olá Bom dia me chamo Karina Pimentel da Cidade Viva! \n","time":"23/01/2026 08:48:07","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Olá! Seja bem-vindo(a).\nFique à vontade para me contar o que aconteceu com seu benefício.\nVou te ouvir com atenção para orientar da melhor forma possível.","time":"23/01/2026 08:52:05"},{"role":"agent","text":"*Karina Pimentel:* Olá, Sr Jonnyert!\n\nNotamos que a sua Renovação de Matrícula ainda não foi realizada e estou entrando em contato para saber se está tudo certo ou se podemos ajudar em algo.\n\nA sua trajetória conosco é importante, e estamos à disposição para esclarecer dúvidas sobre prazos, procedimentos ou qualquer outra necessidade para a continuidade dos seus estudos.\n\nMe diga, sua não renovação foi por motivo técnico ou tem alguma outra necessidade que eu possa te ajudar a resolver?","time":"23/01/2026 09:16:36","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Eu não fiz as provas do primeiro semestre,  o meu pai faleceu em 17 de outubro. Fazia EAD, tentei conversar para me ajudar nessas provas. No EAD são tantos prazos que não tive como cumprir. Achei melhor desistir do Curso, e quando retornar a residir em João Pessoa,  começo de forma PRESENCIAL. \nDesde já,  fico agradecido com o seu retorno. \n\nDeus te abençoe!","time":"23/01/2026 09:31:29"},{"role":"agent","text":"*Karina Pimentel:* Sentimos muito pela sua perda!","time":"23/01/2026 09:42:34","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Estamos a disposição para rever e o senhor retomar o seu curso!","time":"23/01/2026 09:42:55","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Olá Bom dia me chamo Karina Pimentel da Cidade Viva! \n","time":"26/01/2026 09:13:20","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"26/01/2026 09:29:31"},{"role":"client","text":"Sua sessão expirou!","time":"26/01/2026 09:31:33"}]$tag$, $tag$2026-01-23 08:48:07+00$tag$, FALSE, FALSE, 7, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 5, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
