INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$59b6d7eb-d265-4112-9d55-5cf5206b8593$tag$, $tag$2026012600031$tag$, $tag$Ricardo Cesar 🤓 (5595984214417)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Formacao Politica e quero mais informações.","time":"26/01/2026 09:16:07"},{"role":"client","text":"🌟 Bom dia Ricardo Cesar 🤓! Que alegria ter você aqui com a gente! 🙌","time":"26/01/2026 09:16:08"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"26/01/2026 09:16:12"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"26/01/2026 09:16:16"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"26/01/2026 09:16:20"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"26/01/2026 09:16:26"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"26/01/2026 09:16:32"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"26/01/2026 09:16:33"},{"role":"client","text":"Sim, concordo","time":"26/01/2026 09:18:17"},{"role":"client","text":"✅ Obrigado, Ricardo Cesar 🤓! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"26/01/2026 09:18:18"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"26/01/2026 09:18:22"},{"role":"client","text":"Igreja Cidade Viva","time":"26/01/2026 09:19:18"},{"role":"client","text":"🌟 Olá! Que bom ter você aqui conosco na Igreja Cidade Viva!\n\nEste é um espaço onde vivemos juntos fé, comunhão e propósito. 🙏\n\nSe você precisa de apoio, deseja participar de alguma atividade ou quer saber mais sobre o que acontece em nossa comunidade, estamos aqui para ajudar com carinho e atenção. 💛","time":"26/01/2026 09:19:19"},{"role":"client","text":"📝 Antes de continuarmos, para podermos te atender melhor, você poderia me informar seu *CPF*?\n\n🔐 *Em conformidade com a LGPD, seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"26/01/2026 09:19:23"},{"role":"client","text":"02088358730","time":"26/01/2026 09:20:14"},{"role":"client","text":"Selecione no menu abaixo a opção que melhor se encaixa com o que você está buscando:","time":"26/01/2026 09:20:14"},{"role":"client","text":"Igrejas \n Selecione a igreja que você faz parte ou deseja mais informações.","time":"26/01/2026 09:21:20"},{"role":"client","text":"Perfeito! Para te direcionar melhor, por favor escolha abaixo a localização da igreja mais próxima de você:","time":"26/01/2026 09:21:22"},{"role":"client","text":"Voltar ao menu anterior","time":"26/01/2026 09:22:01"},{"role":"client","text":"Selecione no menu abaixo a opção que melhor se encaixa com o que você está buscando:","time":"26/01/2026 09:22:02"},{"role":"client","text":"Outras informações \n saiba como participar de eventos, locações e demais ações.","time":"26/01/2026 09:22:15"},{"role":"client","text":"Ótimo! Por favor, selecione abaixo a opção que deseja ter mais informações sobre:","time":"26/01/2026 09:22:16"},{"role":"client","text":"Voltar ao menu principal","time":"26/01/2026 09:22:38"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"26/01/2026 09:22:39"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"26/01/2026 09:23:15"},{"role":"client","text":"Olá! Ricardo Cesar 🤓!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"26/01/2026 09:23:17"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"26/01/2026 09:23:25"},{"role":"client","text":"Falar com um atendente","time":"26/01/2026 09:23:50"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"26/01/2026 09:23:52"},{"role":"client","text":"Conhecer as ofertas de cursos.","time":"26/01/2026 09:24:18"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"26/01/2026 09:25:01"},{"role":"client","text":"Oi lá, Karina!\nBom dia!\nAz seja contigo.","time":"26/01/2026 09:25:49"},{"role":"client","text":"Vi um POST da CV no Facebook e resolvi conhecer","time":"26/01/2026 09:26:18"},{"role":"client","text":"Já sou Bacharel em Teologia, pela FACETEN, Boa Vista-RR, Brasil.","time":"26/01/2026 09:26:54"},{"role":"client","text":"O que a CV oferece  de continuidade de formação acadêmica, no segmento da Teologia?","time":"26/01/2026 09:27:41"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"26/01/2026 09:29:28","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Era reconhecida pelo MEC?","time":"26/01/2026 09:29:36","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Skin.","time":"26/01/2026 11:14:56"},{"role":"client","text":"Sim","time":"26/01/2026 11:15:00"},{"role":"client","text":"Arquivo | (https://igrejabatista.widechat.com.br/config/storage/view/697777d24f848f7b99035f65)","time":"26/01/2026 11:18:59"},{"role":"client","text":"Não está muito visível.\nMas, tenho o original","time":"26/01/2026 11:20:16"},{"role":"agent","text":"*Karina Pimentel:* O senhor deseja realizar transferência? ","time":"26/01/2026 11:21:57","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não!\nGostaria de saber quais as pós disponíveis, na área de Teologia, nessa instituição","time":"26/01/2026 15:37:09"},{"role":"agent","text":"*Karina Pimentel:* PÓS GRADUAÇÕES: Liderança Cristã, Educação Cristã Clássica, Novo Testamento, Teologia Sistemática, Missiologia Urbana, Ciência Politica e Atuação Pública, Gestão Escolar, Psicopedagogia e Psicoteologia.\n","time":"26/01/2026 16:24:36","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*   Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"27/01/2026 08:34:41","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Bom dia!\nPaz seja contigo.\n\nNão! Não ficou dúvidas.\n\nEstou estudando o que fazer.\n\nO Eterno te abençoe","time":"27/01/2026 08:41:48"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"27/01/2026 09:43:52","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nRicardo Cesar 🤓, esperamos que sua solicitação tenha sido totalmente resolvi