INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$c3030b98-88d5-4e78-9858-52cfa29a18c3$tag$, $tag$2026012600032$tag$, $tag$AndrÃ© Barcelos (5583988265566)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia","time":"26/01/2026 09:23:37"},{"role":"client","text":"🌟 Bom dia AndrÃ© Barcelos! Que alegria ter você aqui com a gente! 🙌","time":"26/01/2026 09:23:38"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"26/01/2026 09:23:42"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"26/01/2026 09:23:46"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"26/01/2026 09:23:50"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"26/01/2026 09:23:56"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"26/01/2026 09:24:02"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"26/01/2026 09:24:04"},{"role":"client","text":"Sim, concordo","time":"26/01/2026 09:24:22"},{"role":"client","text":"✅ Obrigado, AndrÃ© Barcelos! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"26/01/2026 09:24:23"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"26/01/2026 09:24:27"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"26/01/2026 09:26:37"},{"role":"client","text":"Olá! AndrÃ© Barcelos!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"26/01/2026 09:26:38"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"26/01/2026 09:26:42"},{"role":"client","text":"Falar com um atendente","time":"26/01/2026 09:26:55"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"26/01/2026 09:26:56"},{"role":"client","text":"condições do Curso de Teologia para membros/voluntários da Cidade aviva","time":"26/01/2026 09:27:52"},{"role":"client","text":"Cidade Viva","time":"26/01/2026 09:28:09"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"26/01/2026 10:27:40"},{"role":"client","text":"Olá Karina, bom dia.","time":"26/01/2026 10:28:10"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"26/01/2026 10:28:31","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Seria presencial ou Ead?","time":"26/01/2026 10:28:40","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"EAD","time":"26/01/2026 10:28:54"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"26/01/2026 10:29:19","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"26/01/2026 10:29:41","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/69776d5c518124fe7f022577)","time":"26/01/2026 10:34:20"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"26/01/2026 11:01:05","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Conseguimos sim!","time":"26/01/2026 11:01:11","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* 30% de desconto!","time":"26/01/2026 11:01:21","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6977753c06ec8e3d98087801)","time":"26/01/2026 11:07:57"},{"role":"client","text":"R$279,79 mensal","time":"26/01/2026 11:22:00"},{"role":"client","text":"qual o procedimento para a matrícula?","time":"26/01/2026 11:22:15"},{"role":"client","text":"vou fazer","time":"26/01/2026 11:22:19"},{"role":"agent","text":"*Karina Pimentel:* R$ 279,79 (mensais)","time":"26/01/2026 11:35:27","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"26/01/2026 11:35:52","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"tem algum código de voucher ?","time":"26/01/2026 11:57:02"},{"role":"client","text":"para o desconto","time":"26/01/2026 11:57:06"},{"role":"agent","text":"*Karina Pimentel:* Tem sim.","time":"26/01/2026 11:59:07","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* BOLSA30","time":"26/01/2026 11:59:10","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*   Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"27/01/2026 08:33:18","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"olá Karina","time":"27/01/2026 08:35:06"},{"role":"client","text":"Bom dia","time":"27/01/2026 08:35:09"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/6978a3a4cc79ffb9bf05fd30)","time":"27/01/2026 08:38:12"},{"role":"agent","text":"*Karina Pimentel:* Certo!","time":"27/01/2026 09:39:31","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Educação Cristã tem 50% de desconto!","time":"27/01/2026 09:39:46","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Mensalidades de R$ 239,58 (16 mensalidades)","time":"27/01/2026 09:41:53","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n","time":"27/01/2026 09:42:04","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*   Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"27/01/2026 18:24:11","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"olá Karine","time":"27/01/2026 19:25:37"},{"role":"client","text":"estou procura do meu Histórico, minha universidade é do RN, não quero quer que pedir uma segunda via","time":"27/01/2026 19:26:13"},{"role":"agent","text":"*Karina Pimentel:* Olá Bom dia me chamo Karina Pimentel da Cidade Viva! \n","time":"29/01/2026 10:04:14","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nAndrÃ© Barcelos, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"29/01/2026 18:09:17"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"29/01/2026 18:09:18"},{"role":"client","text":"AndrÃ© Barcelos, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"29/01/2026 18:24:19"}]$tag$, $tag$2026-01-26 09:23:37+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 1