INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$75c8461f-d2b3-465f-8e23-83d13943f4d0$tag$, $tag$2026012300065$tag$, $tag$Gislaine Cristina Klein Klein (5549998000307)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Bom dia","time":"23/01/2026 09:36:09"},{"role":"client","text":"🌟 Bom dia Gislaine Cristina Klein Klein! Que alegria ter você aqui com a gente! 🙌","time":"23/01/2026 09:36:10"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"23/01/2026 09:36:14"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"23/01/2026 09:36:18"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"23/01/2026 09:36:26"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"23/01/2026 09:36:34"},{"role":"client","text":"Olá! Gislaine Cristina Klein Klein!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"23/01/2026 09:36:35"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"23/01/2026 09:36:40"},{"role":"client","text":"Falar com um atendente","time":"23/01/2026 09:36:51"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"23/01/2026 09:36:52"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"23/01/2026 09:38:15"},{"role":"agent","text":"*Thayanne Sales:* No que posso lhe ajudar?","time":"23/01/2026 09:38:23","feedback":"⚠️ Pergunta Genérica: Evite perguntas que podem ser respondidas com \"não\". Tente: \"Qual sua maior motivação para estudar hoje?\""},{"role":"client","text":"Revisar contrato da pós graduação em Psicopedagogia, ganhei um cupom de desconto, porém o mesmo não foi aplicado. Realizado a inscrição, mas o contrato saiu com o valor &quot;cheio&quot; da mensalidade, sendo assim, não posso cursar, pois não consigo pagar esse valor.","time":"23/01/2026 09:38:37"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/69736be2b1ae8dc4c403e216)","time":"23/01/2026 09:38:58"},{"role":"client","text":"No dia 05/01 vocês enviaram um link e um cupom","time":"23/01/2026 09:40:05"},{"role":"client","text":"Poderia verificar por gentileza a minha inscrição?","time":"23/01/2026 09:40:26"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/69736ceb9ed90c09bf0366fd)","time":"23/01/2026 09:43:24","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/69736d031f23b5db1b0ffef6)","time":"23/01/2026 09:43:47","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok. Entendi. Obrigada","time":"23/01/2026 09:54:24"},{"role":"client","text":"Essa primeira mensalidade, faz jus a matrícula? Também tem desconto?","time":"23/01/2026 09:54:50"},{"role":"agent","text":"*Thayanne Sales:* Sim, todas as mensalidades com desconto","time":"23/01/2026 09:56:58","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok. Irei finalizar o meu contato. Obrigada","time":"23/01/2026 09:57:28"},{"role":"client","text":"Deus abençoe","time":"23/01/2026 09:57:33"},{"role":"agent","text":"*Thayanne Sales:* Assim que efetuar o pagamento, me enva o comprovante ","time":"23/01/2026 09:58:19","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Que ja solicito baixa","time":"23/01/2026 09:58:24","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6973842fe366a3d05f0162f4)","time":"23/01/2026 11:22:40"},{"role":"client","text":"Comprovante saiu no nome do meu marido","time":"23/01/2026 11:23:33"},{"role":"client","text":"Gislaine Cristina Klein \n04230693907","time":"23/01/2026 11:24:55"},{"role":"client","text":"No momento é só esse valor, aguardo iniciar em abril para pagar as demais mensalidades?","time":"23/01/2026 11:25:24"},{"role":"agent","text":"*Thayanne Sales:* Exatamente","time":"23/01/2026 11:30:01","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Que maravilha, seja muito bem-vinda a Faculdade Internacional Cidade Viva","time":"23/01/2026 11:30:21","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Agora é só aguardar as aulas iniciarem em abril e o acesso as aulas será enviado para o seu e-mail em abril também. \n\nLhe ajudo em algo mais?","time":"23/01/2026 11:30:47","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não. Obrigada","time":"23/01/2026 11:31:49"},{"role":"client","text":"Obrigada 😃","time":"23/01/2026 11:32:01"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e um ótimo final de semana.","time":"23/01/2026 11:32:17","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nGislaine Cristina Klein Klein, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"23/01/2026 11:32:27"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"23/01/2026 11:32:28"},{"role":"client","text":"5","time":"23/01/2026 11:33:43"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"23/01/2026 11:33:44"},{"role":"client","text":"Gislaine Cristina Klein Klein, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"23/01/2026 11:48:45"}]$tag$, $tag$2026-01-23 09:36:09+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 10, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commer