INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$9fae27a8-fb7d-4fde-a8ff-2d41214e1cbc$tag$, $tag$2026012300164$tag$, $tag$Não identificado (910290484681593)$tag$, NULL, $tag$Desconhecido$tag$, $tag$[{"role":"client","text":"Olá, boa tarde.\nSou a Hellen, se possível, gostaria de receber informações sobre a Pós-graduação em Educação Cristã Clássica. Gostaria de saber se ainda é possível se matricular e o valor.\n\nRecebi indicação da minha amiga Roberta Cavalcante, para fazer essa pós com  vocês.\n\nDesde já, agradeço pela atenção!\n\nHellen Ferreira Ramos de Jesus","time":"23/01/2026 16:53:45"},{"role":"client","text":"Olá aguarde só um momento que em breve alguém da nossa equipe irá te responder.","time":"23/01/2026 16:53:46"},{"role":"client","text":"Se puderem enviar as informações pelo Whatsapp","time":"23/01/2026 16:54:21"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"23/01/2026 16:55:09"},{"role":"client","text":"Atendimento Finalizado!\n\n, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"23/01/2026 17:01:12"},{"role":"client","text":"Obrigado por entrar em contato conosco!\n\nVolte sempre!","time":"23/01/2026 17:01:14"}]$tag$, $tag$2026-01-23 16:53:45+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 3, 2, 9, 0, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$8b5c5368-894a-41bc-8027-60a54feab515$tag$, $tag$2026012300166$tag$, $tag$Hellen Ferreira (5581999043419)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde me chamo Thayanne Sales da Cidade Viva! \n","time":"23/01/2026 17:00:09","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Olá, Thayane, boa noite.\nPerdão pelo horário. \nQuando puder, me fala se ainda dá tempo de fazer a matrícula para a Pós em Educação Cristã Clássica.","time":"23/01/2026 19:08:50"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia me chamo Thayanne Sales da Cidade Viva! \n","time":"26/01/2026 08:52:27","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia, Thayane.\nMuito obrigada por entrar em contato.\nEu estava em treinamento na escola.","time":"26/01/2026 12:02:23"},{"role":"client","text":"Eu estou muito desejosa de fazer a Pós-graduação em Educação Cristã Clássica.\nMinha amiga que me indicou fazer com vocês.\nEu gostaria de saber o valor e como faço para fazer a matrícula. 🙏🏻","time":"26/01/2026 12:04:18"},{"role":"agent","text":"*Thayanne Sales:* Certo, vou lhe enviar as informações sobre o curso ","time":"26/01/2026 12:06:11","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"26/01/2026 12:06:21","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Educação Cristã Clássica* - Disciplinas do Curso:\n\nBase: Filosófica Teológica\nCosmovisão Cristã e Filosofia Reformada – Ms. Vinicius Pimentel\nFundamentos da Pedagogia Cristã – Ms. Igor Miguel\nA Paideia de Deus (Educação Pactual) – Ms. Rodrigo Brotto\n\nBase: Histórica Pedagógica Clássica&nbsp;\nHistória da Educação Clássica – Ms. Lucas Evangelista\nFundamentos Pedagógicos das Sete Artes Liberais – Ms. Rodrigo Brotto\nVerdade, Bondade e Beleza: A Formação do Imaginário – Ms. Raquel Van De Burgt\n\nBase: Metodológica Cristã Clássica\nAplicando o Trivium no Contexto Educacional – Ms. Renata Costa\nAprendendo a Ler Classicamente (Alfabetização Clássica) – Esp. Leandro Ribeiro\nDisciplina na Educação (Pastoreando o Coração da Criança) – Ms. Kenneth V. Trotter\nDesenvolvimento do Currículo - Kim Bedinfield\n\nObs: Professores sujeitos a alterações. ","time":"26/01/2026 12:06:24","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. Esta com condições especiais com 50% de desconto e as mensalidades está por R$ 239,58 \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para abril/2026.\n\n\n🎁 Cupom de Desconto ECC: *BOLSA50*\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_19\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"26/01/2026 12:06:32","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Puxa, que maravilha esse desconto. \nMuito obrigada! 😍","time":"26/01/2026 12:21:05"},{"role":"client","text":"Duas amigas minha, também querem fazer. Posso te passar o contato delas para vc entrar em contato e enviar essas informações?\nOu eu mesma posso enviar essas informações para elas e elas te enviam o comprovante da matrícula?","time":"26/01/2026 12:31:55"},{"role":"agent","text":"*Thayanne Sales:* Pode enviar sim as informações para elas","time":"26/01/2026 17:17:39","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok, obrigada.","time":"26/01/2026 17:33:43"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"27/01/2026 10:59:59","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Bom dia.\nAinda não porque estou sem poder pagar a vista agora. Teria que esperar receber.\nPoderia ser a vista no cartão de crédito?","time":"27/01/2026 11:06:50"},{"role":"client","