INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$fedef914-dcac-4e1c-a1f8-f37cc634d8bc$tag$, $tag$2026012600046$tag$, $tag$Muller Miranda (5583988267001)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"26/01/2026 09:48:23"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"26/01/2026 09:48:25"},{"role":"client","text":"Olá, gostaria de saber sobre o vestibular agendado para o curso de teologia ead e sobre os descontos ofertados","time":"26/01/2026 09:51:07"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"26/01/2026 10:33:33"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"26/01/2026 10:34:03","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"26/01/2026 10:34:14","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Há essa possibilidade? O Ricardo Aragão que me informou ontem","time":"26/01/2026 10:36:05"},{"role":"agent","text":"*Karina Pimentel:* O vestibular será apenas uma redação!","time":"26/01/2026 11:01:50","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* O senhor realiza a sua inscrição e já vai disponibilizar a sua redação!","time":"26/01/2026 11:02:27","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Karina Pimentel:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"26/01/2026 11:02:44","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Tenho a nota do enem","time":"26/01/2026 11:34:59"},{"role":"client","text":"Há desconto ?","time":"26/01/2026 11:35:05"},{"role":"agent","text":"*Karina Pimentel:* ENEM seria somente uma das formas de ingresso, não teria descontos!","time":"26/01/2026 11:45:42","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendo","time":"26/01/2026 11:46:53"},{"role":"client","text":"Da mesma forma o vestibular ? Não há desconto, isso ?","time":"26/01/2026 11:47:12"},{"role":"agent","text":"*Karina Pimentel:* Isso, as formas de ingresso não teria descontos!","time":"26/01/2026 11:47:36","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok","time":"26/01/2026 11:48:02"},{"role":"agent","text":"*Karina Pimentel:*   Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"27/01/2026 08:31:14","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Bom dia","time":"27/01/2026 08:47:17"},{"role":"client","text":"Realmente desejo a muito tempo mas as condições financeiras ainda impedem","time":"27/01/2026 08:47:38"},{"role":"client","text":"Irir tentar o vestibular para o presencial mas estarei viajando no dia 😓","time":"27/01/2026 08:47:56"},{"role":"agent","text":"*Karina Pimentel:* Compreendemos!","time":"27/01/2026 09:45:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Já preencheu o requerimento de descontos?","time":"27/01/2026 09:46:06","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:*  \n https://bit.ly/RequerimentodeDescont