INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$10017b8e-8a7d-4500-b681-2733b7cb7093$tag$, $tag$2026012600158$tag$, $tag$Eduardo Diniz (5583988891526)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Bom dia","time":"26/01/2026 13:39:17"},{"role":"client","text":"🌟 Boa tarde Eduardo Diniz! Que alegria ter você aqui com a gente! 🙌","time":"26/01/2026 13:39:18"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"26/01/2026 13:39:22"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"26/01/2026 13:39:26"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"26/01/2026 13:39:30"},{"role":"client","text":"Gostaria de saber mais sobre o curso de teologia","time":"26/01/2026 13:39:31"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"26/01/2026 13:39:32"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"26/01/2026 13:39:37"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"26/01/2026 13:39:43"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"26/01/2026 13:39:44"},{"role":"client","text":"Sim, concordo","time":"26/01/2026 13:46:02"},{"role":"client","text":"✅ Obrigado, Eduardo Diniz! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"26/01/2026 13:46:03"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"26/01/2026 13:46:07"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"26/01/2026 13:46:42"},{"role":"client","text":"Olá! Eduardo Diniz!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"26/01/2026 13:46:43"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"26/01/2026 13:46:46"},{"role":"client","text":"Saber sobre os cursos","time":"26/01/2026 13:47:00"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"26/01/2026 13:47:04"},{"role":"client","text":"Graduação","time":"26/01/2026 13:47:32"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"26/01/2026 13:47:36"},{"role":"client","text":"Teologia (Presencial)","time":"26/01/2026 13:47:50"},{"role":"client","text":"✨ Você escolheu a modalidade presencial em João Pessoa!\nEssa é uma graduação com estrutura moderna, ensino prático desde o início e visão teológica fundamentada nas Escrituras, na tradição dos apóstolos e dos Pais da Igreja.\n\n\n 🎓 Curso reconhecido pelo MEC\n 🔠 Ensino de Grego e Hebraico\n 📌 Prática eclesiástica e liderança desde o início\n 🪙 Matrículas abertas com vagas promocionais!\n","time":"26/01/2026 13:47:51"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"26/01/2026 13:47:56"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"26/01/2026 13:48:39"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"26/01/2026 13:48:40"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"26/01/2026 13:49:49"},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"26/01/2026 13:50:09","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:*  A nossa *Graduação em Teologia Presencial* é Bacharelado e reconhecida pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato presencial as aulas acontecem de segunda à quinta-feira das 19h00 às 22h00 aqui no Polo João Pessoa, localizado na Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.\n\nA nossa base filosófica e teológica é fundamentada na cosmovisão cristã, utilizando o método histórico-gramatical para a interpretação das Sagradas Escrituras. Como Faculdade, diferenciamo-nos de um seminário, que geralmente segue um viés denominacional. Contamos com professores de diferentes tradições cristãs, como Presbiteriana, Batista, Adventista e Anglicana, valorizando assim a integridade intelectual. Todos os nossos docentes são especializados nas suas áreas de atuação.","time":"26/01/2026 13:50:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"26/01/2026 13:50:35","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A mensalidade da Graduação Presencial em Teologia fica R$ 549,56.\n\n🤩 Estamos com uma condição especial, *desconto de 30%* na pontualidade durante toda graduação, que fica apenas R$ 384,69.  *Usando o cupom de desconto: BOLSA30*\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas.\n\n🌟 *Valor promocional:* (Semestralidade R$ 2.308,15).\n\n⚠ *Valor mensal está sujeito a mudança de acordo a data de matrícula:*\n \nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 384,69 = R$ 2.308,15\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 461,63 = R$ 2.308,15\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 577,03 = R$ 2.308,15\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"26/01/2026 13:50:43","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"26/01/2026 13:50:51","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Boa tarde, a matricula tá incluso nesses valores?","time":"26/01/2026 14:01:51"},{"role":"agent","text":"*Thayanne Sales:* Não temos taxa de matricula, o que você paga no ato da inscrição já é a 1ª mensalidade","time":"26/01/2026 14:26:38","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"27/01/2026 10:59:13","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nEduardo Diniz, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"27/01/2026 14:02:24"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"27/01/2026 14:02:25"},{"role":"client","text":"Eduardo Diniz, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"27/01/2026 14:17:26"}]$tag$, $tag$2026-01-26 13:39:17+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 7, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, imp