INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$8176f3d9-6ff8-4acb-b920-b3681ce8baf7$tag$, $tag$2026012600161$tag$, $tag$Lúcia Barreto (5591988880862)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"26/01/2026 13:47:25"},{"role":"client","text":"🌟 Boa tarde Lúcia Barreto! Que alegria ter você aqui com a gente! 🙌","time":"26/01/2026 13:47:26"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"26/01/2026 13:47:30"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"26/01/2026 13:47:34"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"26/01/2026 13:47:42"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"26/01/2026 13:49:49"},{"role":"client","text":"Olá! Lúcia Barreto!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"26/01/2026 13:49:50"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"26/01/2026 13:49:54"},{"role":"client","text":"Saber sobre os cursos","time":"26/01/2026 13:50:07"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"26/01/2026 13:50:11"},{"role":"client","text":"Pós-Graduação","time":"26/01/2026 13:50:26"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"26/01/2026 13:50:30"},{"role":"client","text":"Novo Testamento","time":"26/01/2026 13:51:16"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"26/01/2026 13:51:18"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"26/01/2026 13:51:22"},{"role":"client","text":"História do Cristianismo","time":"26/01/2026 13:51:25"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"26/01/2026 13:51:26"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"26/01/2026 13:51:30"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"26/01/2026 13:51:48"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"26/01/2026 13:51:49"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"26/01/2026 13:52:04"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"26/01/2026 13:52:26"},{"role":"agent","text":"*Thayanne Sales:* O curso ainda não está liberado ","time":"26/01/2026 13:52:46","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Boa tarde.","time":"26/01/2026 13:52:48"},{"role":"agent","text":"*Thayanne Sales:* Boa tarde!","time":"26/01/2026 13:53:05","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"E o Novo Testamento?","time":"26/01/2026 13:54:06"},{"role":"agent","text":"*Thayanne Sales:* Temos sim, vou lhe enviar as informações sobre o curso ","time":"26/01/2026 13:54:31","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"26/01/2026 13:54:51","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*   *Teologia Bíblica e Exegética do Novo Testamento* - Disciplinas do Curso: \n\nCONTEXTO HISTÓRICO DO NOVO TESTAMENTO\nPeríodo Interbíblico e a Formação do Contexto do Novo Testamento\nCosmovisão Judaica, Helênica e Romana do Primeiro Século\nArqueologia Aplicada ao Novo Testamento\n\nTEOLOGIA BÍBLICA DO NOVO TESTAMENTO\nTeologia Bíblica e Exegética dos Evangelhos de Mateus e Marcos\nTeologia Bíblica e Exegética do Evangelho de Lucas e Atos\nTeologia Bíblica e Exegética do Evangelho de João e Suas Cartas\nTeologia Bíblica e Exegética dos Escritos Paulinos I\nTeologia Bíblica e Exegética dos Escritos Paulinos II\nTeologia Bíblica e Exegética das Epístolas Gerais\n﻿Teologia Bíblica e Exegética do Livro do Apocalipse\n\nTEOLOGIA APLICADA À REALIDADE\nFerramentas Exegéticas para Interpretação do Novo Testamento\nTemas Contemporâneos à Luz da Teologia do Novo Testamento\n\nObs: Professores sujeitos a alterações. ","time":"26/01/2026 13:54:56","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok. Obrigada.","time":"26/01/2026 13:54:57"},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37*. Esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026. \n\n🎁 Cupom de Desconto Novo Testamento: *BOLSA50*\n\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_23\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"26/01/2026 13:55:02","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Ok. Obrigada.","time":"26/01/2026 13:56:15"},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nConseguiu fazer a sua matricula?","time":"27/01/2026 10:59:05","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nLúcia Barreto, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"27/01/2026 14:02:29"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"27/01/2026 14:02:32"},{"role":"client","text":"Lúcia Barreto, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"27/01/2026 14:17:34"}]$tag$, $tag$2026-01-26 13:47:25+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 7, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
