INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$f58f2cec-368e-4fc5-8825-df632cad8270$tag$, $tag$2026012600024$tag$, $tag$Pr  Liandro Nunes (5581996943170)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Bom dia","time":"26/01/2026 08:55:33"},{"role":"client","text":"🌟 Bom dia Pr  Liandro Nunes! Que alegria ter você aqui com a gente! 🙌","time":"26/01/2026 08:55:34"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"26/01/2026 08:55:38"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"26/01/2026 08:55:42"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"26/01/2026 08:55:46"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"26/01/2026 08:55:52"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"26/01/2026 08:55:58"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"26/01/2026 08:55:59"},{"role":"client","text":"Sim, concordo","time":"26/01/2026 08:56:26"},{"role":"client","text":"✅ Obrigado, Pr  Liandro Nunes! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"26/01/2026 08:56:27"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"26/01/2026 08:56:30"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"26/01/2026 08:57:10"},{"role":"client","text":"Olá! Pr  Liandro Nunes!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"26/01/2026 08:57:11"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"26/01/2026 08:57:16"},{"role":"client","text":"Saber sobre os cursos","time":"26/01/2026 08:58:01"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"26/01/2026 08:58:05"},{"role":"client","text":"Pós-Graduação","time":"26/01/2026 08:58:18"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"26/01/2026 08:58:22"},{"role":"client","text":"Liderança Cristã","time":"26/01/2026 08:58:45"},{"role":"client","text":"Lidere com sabedoria, integridade e propósito.\n 🧭 Curso voltado para líderes de igrejas, ministérios e organizações cristãs\n 🌍 Temas como discipulado, liderança servidora e gestão de equipes\n 📅 Ainda dá tempo de começar este semestre!\n","time":"26/01/2026 08:58:46"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"26/01/2026 08:58:50"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"26/01/2026 08:59:17"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"26/01/2026 08:59:17"},{"role":"client","text":"Ok","time":"26/01/2026 08:59:36"},{"role":"client","text":"Quero saber o tempo de duração do curso, a grade curricular, os professores, preço e se é só online ou tem aulas presencial?","time":"26/01/2026 09:04:43"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"26/01/2026 09:07:00"},{"role":"agent","text":"*Thayanne Sales:* &nbsp;Olá Bom dia! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"26/01/2026 09:07:08","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:*  *Pós-graduação em Liderança Cristã*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO E CARGA HORÁRIA\nO curso tem duração de 16 meses, com carga horária de 400h.\n\nDISCIPLINAS\nContamos com um total de 10 disciplinas.\n\nAULAS E AVALIAÇÕES\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas. As avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigatoriedade de TCC.","time":"26/01/2026 09:08:28","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  *Liderança Cristã* - Disciplinas do Curso:\n\n*A Vida e a Cosmovisão do Líder*\nCosmovisão Cristã\nA espiritualidade do Líder\n\n*A Igreja, seus propósitos e a Sua missão*\nOs propósitos da Igreja I\nOs propósitos da Igreja II\n\n*Liderança Missional e prática ministerial*\nTeologia Bíblica da Liderança\nLiderança Eclesiástica\nTeologia e Prática da Pregação Expositiva\nGestão Eclesiástica\nPlantação de Igrejas Missionais\n\n*Igrejas que transformam o Brasil*\nIgrejas que transformam o Brasil\nMódulo Optativo - ITB Aplicado (Parceria Rede Godstock)\n\nObs: Professores sujeitos a alterações.","time":"26/01/2026 09:08:33","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Liderança Cristã está em 16 mensalidades de *R$ 359,37*.  Esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026.\n\n🎁 Cupom de Desconto Liderança Cristã: *BOLSA50*\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_22\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"26/01/2026 09:08:45","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Muito obrigado, vou tentar me organizar, o valor está bom mas por enquanto ainda não estou podendo. Quando vai abrir outra turma?","time":"26/01/2026 09:12:12"},{"role":"agent","text":"*Thayanne Sales:* A turma vai iniciar em abril","time":"26/01/2026 09:13:12","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"No próximo ano vai ter?","time":"26/01/2026 09:15:30"},{"role":"client","text":"Ela é online ou tem aulas presencial também?","time":"26/01/2026 09:15:55"},{"role":"agent","text":"*Thayanne Sales:* Deixa eu verificar com a direção se eles liberam mais algum desconto para você","time":"26/01/2026 09:17:27","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Sou pastor, teve uma vez que me mandaram uma promoção que ficou bem acessível na época, foi outro curso, eu não tive como fazer. Esse gostaria muito.","time":"26/01/2026 09:21:21"},{"role":"agent","text":"*Thayanne Sales:* Boa noticia!!! consegui mais 20% de desconto, totalizando 70% de desconto e as mensalidade ficam de R$ 107,81","time":"26/01/2026 10:23:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Vamos prosseguir com a sua matricula ?","time":"26/01/2026 11:53:13","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Tenho um amigo pastor que falei do curso para ele, teria como fazer esse valor para ele também.","time":"26/01/2026 11:58:59"},{"role":"agent","text":"*Thayanne Sales:* Sim","time":"26/01/2026 12:06:51","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"O que precisa para fazer as inscrições?","time":"26/01/2026 12:12:09"},{"role":"agent","text":"*Thayanne Sales:* 🎁 Cupom de Desconto Liderança Cristã: BOLSA70\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_22","time":"26/01/2026 17:18:04","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Thayanne Sales:* Fazer a sua inscrição nesse link, colocar o cupom de desconto acima","time":"26/01/2026 17:18:22","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Thayanne Sales:* E anexar a documentação (caso não tenha toda documentação, saiba que você tem até o final do curso para está nos enviando por e-mail)","time":"26/01/2026 17:19:03","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"No caso o pagamento é para esse mês ou para Abril quando começar as aulas?","time":"26/01/2026 17:44:42"},{"role":"agent","text":"*Thayanne Sales:* Para agora e as demais depois que o curso iniciar em abril","time":"26/01/2026 17:46:34","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Entendi, no caso posso fazer e passar esse mesmo código para o pastor que é meu amigo.","time":"26/01/2026 17:50:01"},{"role":"agent","text":"*Thayanne Sales:* Pode sim","time":"27/01/2026 08:11:28","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nPr  Liandro Nunes, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"28/01/2026 08:07:18"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"28/01/2026 08:07:20"},{"role":"client","text":"Pr  Liandro Nunes, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"28/01/2026 08:22:20"}]$tag$, $tag$2026-01-26 08:55:33+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 14, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attemp